// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract PostingBoard {
    // State variables
    uint256 public postCount;

    // Struct definition for a post
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    // Mappings
    mapping(uint256 => Post) public posts;
    mapping(address => uint256) public authorBalances;

    // Events
    event PostCreated(uint256 indexed postId, address indexed author, string content);
    event PostBoosted(uint256 indexed postId, address indexed booster, uint256 amount, uint256 newTotalPower);
    event Withdrawal(address indexed author, uint256 amount);

    // Modifiers
    modifier postExists(uint256 postId) {
        require(postId > 0 && postId <= postCount, "Post does not exist");
        _;
    }

    // Create a new post
    function createPost(string calldata content) external returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");

        postCount++;
        uint256 newPostId = postCount;

        posts[newPostId] = Post({
            author: msg.sender,
            content: content,
            totalPower: 0
        });

        emit PostCreated(newPostId, msg.sender, content);
        return newPostId;
    }

    // Boost a post with ETH
    function boostPost(uint256 postId) external payable postExists(postId) {
        require(msg.value > 0, "Must send ETH to boost");

        Post storage post = posts[postId];
        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;

        emit PostBoosted(postId, msg.sender, msg.value, post.totalPower);
    }

    // Withdraw accumulated balance
    function withdraw() external {
        uint256 balance = authorBalances[msg.sender];
        require(balance > 0, "No balance to withdraw");

        // Clear balance before transfer to prevent reentrancy
        authorBalances[msg.sender] = 0;

        (bool success, ) = payable(msg.sender).call{value: balance}("");
        require(success, "Transfer failed");

        emit Withdrawal(msg.sender, balance);
    }

    // Receive function to accept ETH (optional, for direct donations)
    receive() external payable {}
}
